object Solution { def versioned_kv_with_snapshot(operations: Seq[Seq[Any]]): Seq[Any] = { val history = scala.collection.mutable.Map[String, scala.collection.mutable.ArrayBuffer[Int]](); val table = scala.collection.mutable.Map[(String, Int), Any](); val out = scala.collection.mutable.ArrayBuffer[Any](); def setAt(key: String, ts: Int, value: Any): Unit = { val stamps = history.getOrElseUpdate(key, scala.collection.mutable.ArrayBuffer[Int]()); val pos = lowerBound(stamps, ts); if (pos == stamps.length || stamps(pos) != ts) stamps.insert(pos, ts); table((key, ts)) = value }; def valueAt(key: String, ts: Int): Any = { val stamps = history.getOrElse(key, scala.collection.mutable.ArrayBuffer[Int]()); val pos = upperBound(stamps, ts); if (pos == 0) null else table((key, stamps(pos - 1))) }; for (op <- operations) op(0).toString match { case "SET" => setAt(op(1).toString, asInt(op(3)), op(2)); case "DELETE" => setAt(op(1).toString, asInt(op(2)), null); case "GET" => out += valueAt(op(1).toString, asInt(op(2))); case "SNAPSHOT" => val ts = asInt(op(1)); out += history.keys.flatMap { key => val value = valueAt(key, ts); if (value == null) None else Some(key -> value) }.toMap; case _ => () }; out.toSeq }; private def lowerBound(values: scala.collection.mutable.ArrayBuffer[Int], target: Int): Int = { var lo = 0; var hi = values.length; while (lo < hi) { val mid = (lo + hi) / 2; if (values(mid) < target) lo = mid + 1 else hi = mid }; lo }; private def upperBound(values: scala.collection.mutable.ArrayBuffer[Int], target: Int): Int = { var lo = 0; var hi = values.length; while (lo < hi) { val mid = (lo + hi) / 2; if (values(mid) <= target) lo = mid + 1 else hi = mid }; lo }; private def asInt(value: Any): Int = value match { case n: Int => n; case n: Long => n.toInt; case n: Double => n.toInt; case _ => 0 } }
